import React, { useState, useEffect, useRef } from 'react';
import { ShoppingBag, Search, ShoppingCart, MessageCircle, UserCircle, LogOut, Package, Plus, Minus, X, Send, ChevronLeft, ChevronRight } from 'lucide-react';

const ProductsPage = ({
	user,
	products,
	cart,
	searchQuery,
	setSearchQuery,
	setCurrentPage,
	handleLogout,
	addToCart,
	error,
	setError
}) => {
	const [chatOpen, setChatOpen] = useState(false);
	const [chatMessages, setChatMessages] = useState([]);
	const [currentMessage, setCurrentMessage] = useState('');
	const [isTyping, setIsTyping] = useState(false);
	const [showSuggestions, setShowSuggestions] = useState(false);
	const [currentBanner, setCurrentBanner] = useState(0);
	const chatEndRef = useRef(null);

	useEffect(() => {
		chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
	}, [chatMessages]);

	// Auto-rotate banner
	useEffect(() => {
		const timer = setInterval(() => {
			setCurrentBanner(prev => (prev + 1) % 3);
		}, 5000);
		return () => clearInterval(timer);
	}, []);

	// Filter products based on search query
	const filteredProducts = (products || []).filter(product =>
		product && (
			(typeof product.name === 'string' && product.name.toLowerCase().includes(searchQuery.toLowerCase())) ||
			(typeof product.brand === 'string' && product.brand.toLowerCase().includes(searchQuery.toLowerCase())) ||
			(typeof product.category === 'string' && product.category.toLowerCase().includes(searchQuery.toLowerCase())) ||
			(typeof product.categoryName === 'string' && product.categoryName.toLowerCase().includes(searchQuery.toLowerCase())) ||
			(typeof product.description === 'string' && product.description.toLowerCase().includes(searchQuery.toLowerCase()))
		)
	);

	// Generate suggestions based on search query
	const suggestions = searchQuery.trim() 
		? filteredProducts.slice(0, 8)
		: [];

	// Extract unique categories as strings only
	const uniqueCategories = Array.from(
		new Set(
			(products || [])
				.map(p => {
					const cat = p.categoryName || p.category || 'Uncategorized';
					return typeof cat === 'string' ? cat : String(cat);
				})
				.filter(Boolean)
		)
	).slice(0, 20);

	const applyCategory = (cat) => {
		setSearchQuery(cat === '' ? '' : cat);
	};

	const quickView = (p) => {
		alert(`${p.name}\n\n${p.brand || ''}\n\n₹${p.price}\n\n${p.description || ''}`);
	};

	const sendMessageToAgent = async (message) => {
		setIsTyping(true);

		const userMsg = { role: 'user', content: message };
		setChatMessages(prev => [...prev, userMsg]);
		setCurrentMessage('');

		setTimeout(() => {
			let agentResponse = '';
			const lowerMsg = message.toLowerCase();

			if (lowerMsg.includes('hi') || lowerMsg.includes('hello')) {
				agentResponse = "Hello! I'm your AI shopping assistant. I can help you find products, add items to cart, or answer questions about your orders. What are you looking for today?";
			} else if (lowerMsg.includes('smartphone') || lowerMsg.includes('phone')) {
				const phones = products.filter(p => p.category === 'Electronics');
				if (lowerMsg.includes('under') || lowerMsg.includes('below')) {
					agentResponse = "I found some great smartphones under ₹10,000! Here's the best option:\n\n📱 Premium Smartphone X1 by TechBrand\nPrice: ₹9,999\nRating: 4.5/5 (1,250 reviews)\nFeatures: 6GB RAM, 128GB Storage, 48MP Camera\n\nWould you like me to add this to your cart?";
				} else {
					agentResponse = `I found ${phones.length} smartphones for you! The Premium Smartphone X1 is our top pick with excellent camera and battery life. Would you like more details?`;
				}
			} else if (lowerMsg.includes('add') && lowerMsg.includes('cart')) {
				if (products.length > 0) {
					addToCart(products[0], setError);
					agentResponse = `Great choice! I've added ${products[0].name} to your cart. Your cart now has ${cart.length + 1} items. Would you like to continue shopping or proceed to checkout?`;
				}
			} else if (lowerMsg.includes('cart') || lowerMsg.includes('show')) {
				if (cart.length === 0) {
					agentResponse = "Your cart is currently empty. Would you like me to help you find some products?";
				} else {
					const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
					agentResponse = `You have ${cart.length} items in your cart:\n\n${cart.map(item => `• ${item.productName || item.name} - ₹${item.price} x ${item.quantity}`).join('\n')}\n\nTotal: ₹${total}\n\nReady to checkout?`;
				}
			} else if (lowerMsg.includes('recommend') || lowerMsg.includes('suggest')) {
				agentResponse = "Based on popular choices, I recommend:\n\n1. Premium Smartphone X1 - Best value for money\n2. Wireless Earbuds Pro - Great audio quality\n3. Smart Watch Ultra - Perfect for fitness tracking\n\nWhich category interests you most?";
			} else if (lowerMsg.includes('checkout') || lowerMsg.includes('buy')) {
				agentResponse = "Perfect! To proceed with checkout, I'll need to confirm your shipping address. You have saved addresses. Would you like to use them, or add a new one?";
			} else {
				agentResponse = "I can help you with:\n• Finding products by category or budget\n• Adding items to your cart\n• Checking order status\n• Product recommendations\n\nWhat would you like to do?";
			}

			const assistantMsg = { role: 'assistant', content: agentResponse };
			setChatMessages(prev => [...prev, assistantMsg]);
			setIsTyping(false);
		}, 1000 + Math.random() * 1000);
	};

	const banners = [
		{
			title: "Summer Sale 2026",
			subtitle: "Up to 50% OFF on Electronics",
			description: "Free shipping on orders above ₹999",
			bg: "from-orange-500 to-pink-600"
		},
		{
			title: "New Arrivals",
			subtitle: "Latest Smartphones & Gadgets",
			description: "Shop the newest tech at best prices",
			bg: "from-blue-600 to-indigo-600"
		},
		{
			title: "Special Offer",
			subtitle: "Buy 2 Get 1 Free",
			description: "On selected audio & wearables",
			bg: "from-purple-600 to-pink-600"
		}
	];

	return (
		<div className="min-h-screen bg-gray-50">
			{/* Header - Amazon Style */}
			<header className="bg-gray-900 text-white sticky top-0 z-40">
				{/* Top Bar */}
				<div className="bg-gray-900">
					<div className="max-w-[1500px] mx-auto px-4 py-2 flex items-center justify-between">
						{/* Logo */}
						<div className="flex items-center gap-2 cursor-pointer">
							<ShoppingBag className="w-7 h-7 text-orange-400" />
							<div>
								<h1 className="text-xl font-bold">ShopAI</h1>
								<p className="text-[10px] text-gray-400">.in</p>
							</div>
						</div>

						{/* Search Bar */}
						<div className="hidden md:flex flex-1 max-w-3xl mx-4 relative">
							<select className="bg-gray-200 text-gray-800 px-3 py-2 rounded-l border-r border-gray-300 text-sm focus:outline-none">
								<option>All</option>
								{uniqueCategories.map((cat, i) => (
									<option key={i} value={cat}>{cat}</option>
								))}
							</select>
							<div className="relative flex-1">
								<input
									aria-label="Search products"
									value={searchQuery}
									onChange={(e) => {
										setSearchQuery(e.target.value);
										setShowSuggestions(true);
									}}
									onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
									onFocus={() => setShowSuggestions(true)}
									placeholder="Search ShopAI.in"
									className="w-full px-4 py-2 text-gray-900 focus:outline-none"
								/>

								{/* Suggestions Dropdown */}
								{showSuggestions && searchQuery.trim() && suggestions.length > 0 && (
									<div className="absolute top-full left-0 right-0 bg-white border border-gray-300 shadow-lg z-50 max-h-96 overflow-y-auto">
										{suggestions.map((item, idx) => (
											<div
												key={item.id || idx}
												onMouseDown={() => {
													setSearchQuery(item.name);
													setShowSuggestions(false);
												}}
												className="px-4 py-2 cursor-pointer hover:bg-gray-100 flex justify-between items-center border-b border-gray-200"
											>
												<div className="flex-1">
													<p className="text-sm text-gray-900">{item.name}</p>
													<p className="text-xs text-gray-500">{item.brand || item.category}</p>
												</div>
												<span className="text-sm font-medium text-gray-900">₹{item.price?.toLocaleString()}</span>
											</div>
										))}
									</div>
								)}
							</div>
							<button className="bg-orange-400 hover:bg-orange-500 px-4 py-2 rounded-r">
								<Search className="w-5 h-5 text-gray-900" />
							</button>
						</div>

						{/* Right Side Icons */}
						<div className="flex items-center gap-4">
							<button onClick={() => setCurrentPage('profile')} className="hover:border border-white px-2 py-1 text-xs">
								<div className="text-xs">Hello, {user?.name || 'User'}</div>
								<div className="font-bold text-sm">Account & Lists</div>
							</button>

							<button onClick={() => setCurrentPage('cart')} className="flex items-center gap-1 hover:border border-white px-2 py-1">
								<div className="relative">
									<ShoppingCart className="w-7 h-7" />
									{cart.length > 0 && (
										<span className="absolute -top-1 -right-1 bg-orange-500 text-white text-xs font-bold rounded-full w-5 h-5 flex items-center justify-center">
											{cart.length}
										</span>
									)}
								</div>
								<span className="font-bold text-sm">Cart</span>
							</button>
						</div>
					</div>
				</div>

				{/* Navigation Bar */}
				<div className="bg-gray-800">
					<div className="max-w-[1500px] mx-auto px-4 py-2 flex items-center gap-6 text-sm overflow-x-auto">
						<button className="flex items-center gap-1 hover:border border-white px-2 py-1 whitespace-nowrap">
							<Package className="w-4 h-4" />
							All Categories
						</button>
						{uniqueCategories.slice(0, 8).map((cat, i) => (
							<button
								key={i}
								onClick={() => applyCategory(cat)}
								className={`hover:border border-white px-2 py-1 whitespace-nowrap ${searchQuery === cat ? 'border border-white' : ''}`}
							>
								{cat}
							</button>
						))}
						<button onClick={() => setChatOpen(!chatOpen)} className="flex items-center gap-1 hover:border border-white px-2 py-1 ml-auto whitespace-nowrap">
							<MessageCircle className="w-4 h-4" />
							AI Assistant
						</button>
						<button onClick={handleLogout} className="hover:border border-white px-2 py-1 whitespace-nowrap">
							<LogOut className="w-4 h-4 inline mr-1" />
							Logout
						</button>
					</div>
				</div>
			</header>

			{/* Mobile Search */}
			<div className="md:hidden bg-white p-3 border-b">
				<div className="flex items-center gap-2 bg-gray-100 rounded px-3 py-2">
					<Search className="w-4 h-4 text-gray-500" />
					<input
						aria-label="Search products"
						value={searchQuery}
						onChange={(e) => setSearchQuery(e.target.value)}
						placeholder="Search products..."
						className="flex-1 bg-transparent text-sm focus:outline-none"
					/>
				</div>
			</div>

			<div className="max-w-[1500px] mx-auto px-3">
				{error && (
					<div className="mt-4 bg-red-50 border-l-4 border-red-500 text-red-800 px-4 py-3 mb-4">
						<p className="text-sm">{error}</p>
					</div>
				)}

				{/* Hero Banner Carousel */}
				<div className="relative h-[400px] overflow-hidden mt-4 mb-6 bg-white">
					<div className="absolute inset-0 flex transition-transform duration-500" style={{ transform: `translateX(-${currentBanner * 100}%)` }}>
						{banners.map((banner, idx) => (
							<div key={idx} className="min-w-full h-full relative">
								<div className={`absolute inset-0 bg-gradient-to-r ${banner.bg}`}>
									<div className="max-w-2xl h-full flex flex-col justify-center px-12 text-white">
										<h2 className="text-5xl font-bold mb-4">{banner.title}</h2>
										<p className="text-2xl mb-2">{banner.subtitle}</p>
										<p className="text-lg mb-6">{banner.description}</p>
										<button
											onClick={() => setSearchQuery('')}
											className="w-fit px-6 py-3 bg-white text-gray-900 font-medium rounded hover:bg-gray-100 transition"
										>
											Shop now
										</button>
									</div>
								</div>
							</div>
						))}
					</div>

					{/* Banner Navigation */}
					<button
						onClick={() => setCurrentBanner(prev => (prev - 1 + banners.length) % banners.length)}
						className="absolute left-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full shadow-lg"
					>
						<ChevronLeft className="w-6 h-6 text-gray-900" />
					</button>
					<button
						onClick={() => setCurrentBanner(prev => (prev + 1) % banners.length)}
						className="absolute right-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full shadow-lg"
					>
						<ChevronRight className="w-6 h-6 text-gray-900" />
					</button>

					{/* Dots */}
					<div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-2">
						{banners.map((_, idx) => (
							<button
								key={idx}
								onClick={() => setCurrentBanner(idx)}
								className={`w-2 h-2 rounded-full transition ${currentBanner === idx ? 'bg-white w-6' : 'bg-white/50'}`}
							/>
						))}
					</div>
				</div>

				{/* Category Cards Grid - Amazon Style */}
				<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
					{/* Category Card 1 */}
					<div className="bg-white p-5">
						<h3 className="text-xl font-bold mb-4">Revamp your home in style</h3>
						<div className="grid grid-cols-2 gap-3 mb-4">
							<div>
								<img src="https://via.placeholder.com/150" alt="Category" className="w-full mb-2" />
								<p className="text-xs">Cushion covers, bedsheets & more</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Category" className="w-full mb-2" />
								<p className="text-xs">Figurines, vases & more</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Category" className="w-full mb-2" />
								<p className="text-xs">Home storage</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Category" className="w-full mb-2" />
								<p className="text-xs">Lighting solutions</p>
							</div>
						</div>
						<a href="#" className="text-sm text-blue-600 hover:text-orange-600 hover:underline">Explore all</a>
					</div>

					{/* Category Card 2 */}
					<div className="bg-white p-5">
						<h3 className="text-xl font-bold mb-4">Up to 60% off | Electronics</h3>
						<div className="grid grid-cols-2 gap-3 mb-4">
							<div>
								<img src="https://via.placeholder.com/150" alt="Electronics" className="w-full mb-2" />
								<p className="text-xs">Up to 45% off | Laptops</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Electronics" className="w-full mb-2" />
								<p className="text-xs">Up to 60% off | Kitchen appliances</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Electronics" className="w-full mb-2" />
								<p className="text-xs">Min. 50% off | Office furniture</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Electronics" className="w-full mb-2" />
								<p className="text-xs">Register with GST</p>
							</div>
						</div>
						<a href="#" className="text-sm text-blue-600 hover:text-orange-600 hover:underline">See more</a>
					</div>

					{/* Category Card 3 */}
					<div className="bg-white p-5">
						<h3 className="text-xl font-bold mb-4">Appliances for your home</h3>
						<div className="grid grid-cols-2 gap-3 mb-4">
							<div>
								<img src="https://via.placeholder.com/150" alt="Appliances" className="w-full mb-2" />
								<p className="text-xs">Air conditioners</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Appliances" className="w-full mb-2" />
								<p className="text-xs">Refrigerators</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Appliances" className="w-full mb-2" />
								<p className="text-xs">Microwaves</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Appliances" className="w-full mb-2" />
								<p className="text-xs">Washing machines</p>
							</div>
						</div>
						<a href="#" className="text-sm text-blue-600 hover:text-orange-600 hover:underline">See more</a>
					</div>

					{/* Category Card 4 */}
					<div className="bg-white p-5">
						<h3 className="text-xl font-bold mb-4">Starting ₹49 | Deals</h3>
						<div className="grid grid-cols-2 gap-3 mb-4">
							<div>
								<img src="https://via.placeholder.com/150" alt="Deals" className="w-full mb-2" />
								<p className="text-xs">Cleaning supplies</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Deals" className="w-full mb-2" />
								<p className="text-xs">Bathroom accessories</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Deals" className="w-full mb-2" />
								<p className="text-xs">Home tools</p>
							</div>
							<div>
								<img src="https://via.placeholder.com/150" alt="Deals" className="w-full mb-2" />
								<p className="text-xs">Wallpapers</p>
							</div>
						</div>
						<a href="#" className="text-sm text-blue-600 hover:text-orange-600 hover:underline">Explore all</a>
					</div>
				</div>

				{/* Filter & Sort Section */}
				<div className="bg-white p-4 mb-4 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
					<div className="flex items-center gap-3">
						<span className="text-sm font-medium">Sort by:</span>
						<select className="text-sm border border-gray-300 rounded px-3 py-1.5 bg-white focus:outline-none focus:ring-2 focus:ring-blue-500">
							<option value="">Featured</option>
							<option value="price-asc">Price: Low to High</option>
							<option value="price-desc">Price: High to Low</option>
							<option value="rating-desc">Avg. Customer Review</option>
						</select>
					</div>

					<div className="text-sm text-gray-600">
						<span className="font-medium">{filteredProducts.length}</span> results
					</div>
				</div>

				{/* Products Grid */}
				<div className="pb-8">
					{filteredProducts.length === 0 ? (
						<div className="bg-white p-12 text-center">
							<Search className="w-16 h-16 mx-auto text-gray-300 mb-4" />
							<h3 className="text-xl font-bold text-gray-900 mb-2">No products found</h3>
							<p className="text-gray-600 mb-6">Try different keywords or browse categories</p>
							<button 
								onClick={() => setSearchQuery('')} 
								className="px-6 py-2 bg-orange-400 hover:bg-orange-500 text-white font-medium rounded"
							>
								View All Products
							</button>
						</div>
					) : (
						<div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
							{filteredProducts.map(product => (
								<div 
									key={product.id} 
									className="bg-white p-4 hover:shadow-lg transition-shadow border border-gray-200 flex flex-col"
								>
									{/* Product Image */}
									<div className="relative mb-3 bg-gray-50 rounded overflow-hidden aspect-square">
										<img
											src={
												product.imageUrl
													? `/images/${product.imageUrl}`
													: 'https://via.placeholder.com/300x300/f3f4f6/9ca3af?text=Product'
											}
											alt={product.name}
											className="w-full h-full object-contain hover:scale-105 transition-transform"
											onError={(e) => {
												e.currentTarget.src = 'https://via.placeholder.com/300x300/f3f4f6/9ca3af?text=Product';
											}}
										/>
										{product.stockQuantity !== undefined && product.stockQuantity <= 5 && (
											<div className="absolute top-2 left-2 bg-red-600 text-white text-xs font-bold px-2 py-1 rounded">
												Only {product.stockQuantity} left
											</div>
										)}
									</div>

									{/* Product Info */}
									<div className="flex-1 flex flex-col">
										<h3 className="text-sm font-medium text-gray-900 mb-1 line-clamp-2 hover:text-orange-600 cursor-pointer">
											{product.name}
										</h3>

										{/* Rating */}
										{product.rating && (
											<div className="flex items-center gap-1 mb-2">
												<div className="flex items-center">
													{[...Array(5)].map((_, i) => (
														<span key={i} className="text-orange-400 text-xs">
															{i < Math.floor(product.rating) ? '★' : '☆'}
														</span>
													))}
												</div>
												<span className="text-xs text-gray-600">({product.reviewCount || 0})</span>
											</div>
										)}

										{/* Price */}
										<div className="mb-2">
											<div className="flex items-baseline gap-2">
												<span className="text-sm text-red-600">-20%</span>
												<span className="text-2xl font-medium">₹{product.price.toLocaleString()}</span>
											</div>
											<div className="text-xs text-gray-500">
												M.R.P.: <span className="line-through">₹{(product.price * 1.2).toLocaleString()}</span>
											</div>
										</div>

										{/* Brand */}
										<p className="text-xs text-gray-600 mb-3">{product.brand || product.category}</p>

										{/* Action Buttons */}
										<div className="mt-auto space-y-2">
											<button
												onClick={() => addToCart(product, setError)}
												disabled={product.stockQuantity === 0}
												className="w-full px-4 py-2 bg-orange-400 hover:bg-orange-500 text-white text-sm font-medium rounded disabled:opacity-50 disabled:cursor-not-allowed transition"
											>
												{product.stockQuantity === 0 ? 'Out of Stock' : 'Add to Cart'}
											</button>
											<button 
												onClick={() => quickView(product)}
												className="w-full px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-900 text-sm font-medium rounded transition"
											>
												Quick View
											</button>
										</div>
									</div>
								</div>
							))}
						</div>
					)}
				</div>
			</div>

			{/* AI Chat Widget */}
			{chatOpen && (
				<div className="fixed bottom-6 right-6 w-96 bg-white rounded-lg shadow-2xl flex flex-col border border-gray-200 z-50 max-h-[600px]">
					{/* Chat Header */}
					<div className="bg-gray-900 text-white p-4 flex justify-between items-center rounded-t-lg">
						<div className="flex items-center gap-3">
							<div className="w-10 h-10 bg-orange-400 rounded-full flex items-center justify-center">
								<span className="text-lg">🤖</span>
							</div>
							<div>
								<h3 className="font-bold">ShopAI Assistant</h3>
								<p className="text-xs text-gray-300">Online</p>
							</div>
						</div>
						<button 
							aria-label="Close chat" 
							onClick={() => setChatOpen(false)} 
							className="hover:bg-gray-800 p-2 rounded"
						>
							<X className="w-5 h-5" />
						</button>
					</div>

					{/* Chat Messages */}
					<div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50 min-h-[300px] max-h-[400px]">
						{chatMessages.length === 0 && (
							<div className="text-center text-gray-500 mt-8">
								<p className="font-medium mb-2">Hi! How can I help you today?</p>
								<div className="flex flex-wrap gap-2 justify-center mt-4">
									<button 
										onClick={() => sendMessageToAgent('Show me smartphones')}
										className="text-xs bg-white border border-gray-300 px-3 py-1.5 rounded-full hover:bg-gray-100"
									>
										📱 Smartphones
									</button>
									<button 
										onClick={() => sendMessageToAgent('Best budget products')}
										className="text-xs bg-white border border-gray-300 px-3 py-1.5 rounded-full hover:bg-gray-100"
									>
										💰 Budget Items
									</button>
								</div>
							</div>
						)}

						{chatMessages.map((msg, idx) => (
							<div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
								<div className={`max-w-xs px-3 py-2 rounded-lg text-sm ${
									msg.role === 'user' 
										? 'bg-blue-600 text-white' 
										: 'bg-white text-gray-900 border border-gray-200'
								}`}>
									{msg.content}
								</div>
							</div>
						))}

						{isTyping && (
							<div className="flex items-center gap-2 text-gray-600">
								<div className="w-8 h-8 bg-white rounded-full flex items-center justify-center border border-gray-200">
									<div className="flex gap-1">
										<div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></div>
										<div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
										<div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{animationDelay: '0.4s'}}></div>
									</div>
								</div>
								<span className="text-xs">Typing...</span>
							</div>
						)}

						<div ref={chatEndRef} />
					</div>

					{/* Chat Input */}
					<div className="border-t border-gray-200 p-3 bg-white rounded-b-lg flex gap-2">
						<input
							type="text"
							value={currentMessage}
							onChange={(e) => setCurrentMessage(e.target.value)}
							onKeyDown={(e) => {
								if (e.key === 'Enter' && currentMessage.trim() && !isTyping) {
									sendMessageToAgent(currentMessage.trim());
								}
							}}
							placeholder="Type your message..."
							disabled={isTyping}
							className="flex-1 border border-gray-300 rounded px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50"
						/>
						<button 
							onClick={() => {
								if (currentMessage.trim() && !isTyping) {
									sendMessageToAgent(currentMessage.trim());
								}
							}}
							disabled={!currentMessage.trim() || isTyping}
							className="bg-orange-400 hover:bg-orange-500 text-white p-2 rounded disabled:opacity-50 disabled:cursor-not-allowed"
						>
							<Send className="w-5 h-5" />
						</button>
					</div>
				</div>
			)}

			{/* Floating Chat Button */}
			{!chatOpen && (
				<button
					onClick={() => setChatOpen(true)}
					className="fixed bottom-6 right-6 w-14 h-14 bg-orange-400 hover:bg-orange-500 text-white rounded-full shadow-lg flex items-center justify-center z-40 transition"
				>
					<MessageCircle className="w-6 h-6" />
					{chatMessages.length > 0 && (
						<span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center">
							{Math.min(chatMessages.length, 9)}
						</span>
					)}
				</button>
			)}
		</div>
	);
};

export default ProductsPage;
